1	export interface QuoteInput {
2	  customer?: { yearsWithMHPCO: number; previousContracts?: number };
3	  items: { type: string; cursed?: boolean; enchantment?: number }[];
4	}
5	
6	const PROCESSING_FEE = 5;
7	
8	const BLOCK_SIZE = 3;
9	const BLOCK_PRICE = 60;
10	
11	const CURSE_SURCHARGE_RATE = 0.5;
12	
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	
16	const LOYALTY_MINIMUM_YEARS = 2;
17	const LOYALTY_DISCOUNT_RATE = 0.2;
18	
19	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
20	
21	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
22	
23	const BASE_PREMIUMS: Record<string, number> = {
24	  sword: 100,
25	  amulet: 60,
26	  staff: 80,
27	  potion: 40,
28	  rune: 25,
29	  moonstone: 25,
30	};
31	
32	export function quote(input: QuoteInput): number {
33	  const countsByType: Record<string, number> = {};
34	  for (const item of input.items) {
35	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
36	  }
37	
38	  let basePremiumTotal = 0;
39	  for (const type of Object.keys(countsByType)) {
40	    const count = countsByType[type];
41	    if (count === BLOCK_SIZE) {
42	      basePremiumTotal += BLOCK_PRICE;
43	    } else {
44	      basePremiumTotal += count * BASE_PREMIUMS[type];
45	    }
46	  }
47	
48	  const isFirstInsurance = input.customer?.previousContracts === 0;
49	
50	  let surchargeTotal = 0;
51	  for (const item of input.items) {
52	    if (item.cursed) {
53	      surchargeTotal += BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE;
54	    }
55	    if (
56	      item.enchantment !== undefined &&
57	      item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
58	    ) {
59	      surchargeTotal +=
60	        BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
61	    }
62	    if (isFirstInsurance) {
63	      surchargeTotal +=
64	        BASE_PREMIUMS[item.type] * FIRST_INSURANCE_SURCHARGE_RATE;
65	    }
66	  }
67	
68	  const isLoyal =
69	    (input.customer?.yearsWithMHPCO ?? 0) >= LOYALTY_MINIMUM_YEARS;
70	  const isFollowUp = (input.customer?.previousContracts ?? 0) >= 1;
71	
72	  const loyaltyDiscount = isLoyal ? basePremiumTotal * LOYALTY_DISCOUNT_RATE : 0;
73	  const followUpDiscount = isFollowUp
74	    ? basePremiumTotal * FOLLOW_UP_DISCOUNT_RATE
75	    : 0;
76	
77	  return (
78	    basePremiumTotal -
79	    loyaltyDiscount -
80	    followUpDiscount +
81	    surchargeTotal +
82	    PROCESSING_FEE
83	  );
84	}
85	
86	export function claim(): number {
87	  return undefined as unknown as number;
88	}
